// src/three/SceneManager.js
import * as THREE from 'three';
import { OrbitControls } from 'three/examples/jsm/controls/OrbitControls';
import { TransformControls } from 'three/examples/jsm/controls/TransformControls';
import { Room } from './objects/Room';
import { ModelLoader } from './ModelLoader';
import { GridHelper } from './utils/GridHelper';

export class SceneManager {
  constructor(container) {
    this.container = container;
    this.objects = [];
    this.selectedObject = null;
    this.modelLoader = new ModelLoader();
    this.transformMode = 'translate';
    this.undoStack = [];
    this.redoStack = [];
    this.clock = new THREE.Clock();
    this.debug = true;

    this.initScene();
    this.initCamera();
    this.initRenderer();
    this.initLights();
    this.initControls();
    this.initRoom();
    this.initGrid();
    this.initRaycaster();

    if (this.debug) {
      window.addEventListener('model-loading-completed', (event) => {
        console.log('Model loaded:', event.detail.modelType);
      });
      window.addEventListener('model-loading-error', (event) => {
        console.error('Model loading error:', event.detail.error);
      });
    }

    window.addEventListener('resize', this.onWindowResize.bind(this));
    this.container.addEventListener('pointerdown', this.onPointerDown.bind(this));
    this.animate();
  }

  initScene() {
    this.scene = new THREE.Scene();
    this.scene.background = new THREE.Color(0xf0f0f0);
    this.scene.fog = new THREE.Fog(0xf0f0f0, 10, 50);
  }

  initCamera() {
    this.camera = new THREE.PerspectiveCamera(45, this.container.clientWidth / this.container.clientHeight, 0.1, 1000);
    this.camera.position.set(5, 5, 10);
    this.camera.lookAt(0, 0, 0);
  }

  initRenderer() {
    this.renderer = new THREE.WebGLRenderer({ antialias: true, powerPreference: "high-performance" });
    this.renderer.setPixelRatio(window.devicePixelRatio);
    this.renderer.setSize(this.container.clientWidth, this.container.clientHeight);
    this.renderer.shadowMap.enabled = true;
    this.renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    this.renderer.physicallyCorrectLights = true;
    this.renderer.outputColorSpace = THREE.SRGBColorSpace;
    this.container.appendChild(this.renderer.domElement);
  }

  initLights() {
    const ambientLight = new THREE.AmbientLight(0xffffff, 0.5);
    this.scene.add(ambientLight);

    const directionalLight = new THREE.DirectionalLight(0xffffff, 0.8);
    directionalLight.position.set(5, 10, 7.5);
    directionalLight.castShadow = true;
    directionalLight.shadow.mapSize.width = 2048;
    directionalLight.shadow.mapSize.height = 2048;
    const d = 15;
    directionalLight.shadow.camera.left = -d;
    directionalLight.shadow.camera.right = d;
    directionalLight.shadow.camera.top = d;
    directionalLight.shadow.camera.bottom = -d;
    directionalLight.shadow.camera.far = 50;
    this.scene.add(directionalLight);

    const rimLight = new THREE.DirectionalLight(0xffffff, 0.3);
    rimLight.position.set(-5, 5, -5);
    this.scene.add(rimLight);

    const pointLight = new THREE.PointLight(0xffffff, 0.5);
    pointLight.position.set(0, 5, 0);
    pointLight.castShadow = true;
    this.scene.add(pointLight);
  }

  initControls() {
    this.orbitControls = new OrbitControls(this.camera, this.renderer.domElement);
    this.orbitControls.enableDamping = true;
    this.orbitControls.dampingFactor = 0.1;
    this.orbitControls.screenSpacePanning = false;
    this.orbitControls.minDistance = 2;
    this.orbitControls.maxDistance = 30;
    this.orbitControls.maxPolarAngle = Math.PI / 2 - 0.1;

    this.transformControls = new TransformControls(this.camera, this.renderer.domElement);
    this.transformControls.addEventListener('dragging-changed', (event) => {
      this.orbitControls.enabled = !event.value;
    });
    this.transformControls.addEventListener('objectChange', () => {
      if (this.selectedObject) {
        this.updateObjectState(this.selectedObject);
      }
    });
    this.scene.add(this.transformControls);
  }

  initRoom() {
    this.room = new Room(10, 3, 8);
    this.scene.add(this.room.group);
    window.FLOORPLAN = this.room;
  }

  initGrid() {
    this.grid = new GridHelper(30, 30, 0.5);
    this.scene.add(this.grid.grid);
  }

  initRaycaster() {
    this.raycaster = new THREE.Raycaster();
    this.pointer = new THREE.Vector2();
  }

  onWindowResize() {
    this.camera.aspect = this.container.clientWidth / this.container.clientHeight;
    this.camera.updateProjectionMatrix();
    this.renderer.setSize(this.container.clientWidth, this.container.clientHeight);
  }

  onPointerDown(event) {
    this.pointer.x = (event.clientX / this.container.clientWidth) * 2 - 1;
    this.pointer.y = -(event.clientY / this.container.clientHeight) * 2 + 1;
    if (!this.camera) return;
    this.raycaster.setFromCamera(this.pointer, this.camera);
    const selectable = this.objects.filter(o => o.userData.selectable !== false);
    const intersects = this.raycaster.intersectObjects(selectable, true);
    if (intersects.length > 0) {
      let obj = intersects[0].object;
      while (obj.parent && !obj.userData.isModelRoot) obj = obj.parent;
      this.selectObject(obj);
    } else {
      this.deselectObject();
    }
  }

  selectObject(object) {
    this.deselectObject();
    this.selectedObject = object;
    this.transformControls.attach(object);
    this.transformControls.setMode(this.transformMode);
  }

  deselectObject() {
    this.transformControls.detach();
    this.selectedObject = null;
  }

  setView3D() {
    this.camera.position.set(5, 5, 10);
    this.camera.lookAt(0, 0, 0);
    this.orbitControls.update();
  }

  dispose() {
    if (this.animationFrameId) cancelAnimationFrame(this.animationFrameId);
    if (this.orbitControls) this.orbitControls.dispose();
    if (this.transformControls) this.transformControls.dispose();
    if (this.renderer) {
      this.renderer.dispose();
      if (this.container && this.renderer.domElement) {
        this.container.removeChild(this.renderer.domElement);
      }
    }
    this.scene = null;
    this.camera = null;
    this.renderer = null;
    this.orbitControls = null;
    this.transformControls = null;
    this.objects = null;
  }

  animate() {
    this.animationFrameId = requestAnimationFrame(this.animate.bind(this));
    if (this.orbitControls) this.orbitControls.update();
    if (this.clock) this.clock.getDelta();
    if (this.renderer && this.scene && this.camera) {
      this.renderer.render(this.scene, this.camera);
    }
  }
}
